{
  "mitigation_currently_implemented": "Enable Fail2Ban on UbuntuComputer to monitor logs and ban IP addresses exhibiting scanning or brute force behavior",
  "comments": "I enabled Fail2Ban on the UbuntuComputer by configuring a jail for SSH daemon monitoring. The jail is set to enable monitoring of the /var/log/auth.log log file, watching for potential malicious activities such as scanning or brute force login attempts on the SSH service. Fail2Ban will automatically ban IP addresses that show suspicious behavior with a max retry limit of 3 attempts. Then I restarted the Fail2Ban service to activate the configuration. This mitigation provides dynamic protection on the host level to reduce attack success.",
  "device_identifier": "UbuntuComputer",
  "commands": [
    "fail2ban-client status",
    "echo -e \"[sshd]\\nenabled = true\\nport = ssh\\nfilter = sshd\\nlogpath = /var/log/auth.log\\nmaxretry = 3\" > /etc/fail2ban/jail.d/sshd.local",
    "service fail2ban restart"
  ]
}
